import{_ as e}from"./chunks/quickstart_01.CAs9iatn.js";import{_ as i,o as t,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Inicio Rápido","description":"","frontmatter":{},"headers":[],"relativePath":"es/getting-started/quickstart.md","filePath":"es/getting-started/quickstart.md"}'),s={name:"es/getting-started/quickstart.md"};function l(n,a,c,d,p,g){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="inicio-rapido" tabindex="-1"><i class="ph ph-target"></i> Inicio Rápido <a class="header-anchor" href="#inicio-rapido" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-target&quot;&gt;&lt;/i&gt; Inicio Rápido&quot;">​</a></h1><p>El plugin WebAP está diseñado con un enfoque <em>Plug-and-Play</em>. No es necesario escribir código ni agregar gestores a tu escena de inicio: el sistema se inicializa automáticamente.</p><h2 id="_1-activar-el-plugin" tabindex="-1">1. Activar el Plugin <a class="header-anchor" href="#_1-activar-el-plugin" aria-label="Permalink to &quot;1. Activar el Plugin&quot;">​</a></h2><ol><li>Navega a <strong>Edit -&gt; Project Settings -&gt; Adaptive Performance (Web)</strong>.</li><li>Activa la opción <strong>Enable Web Adaptive Performance</strong>.</li><li>Expande la pestaña Scalers y habilita los módulos adicionales que mejor se adapten a las particularidades de tu juego (por ejemplo, paso de física o calidad de sombras) (Consulta <a href="./../scalers/reference">Referencia de Scalers</a> para más detalles).</li></ol><p><img src="'+e+'" alt=""></p><div class="info custom-block"><p class="custom-block-title">Configuración Predeterminada</p><p>Las configuraciones predeterminadas están preconfiguradas para ofrecer un rendimiento óptimo en la mayoría de los proyectos. Mantenlas sin cambios.</p></div><h2 id="_2-configurar-player-settings" tabindex="-1">2. Configurar Player Settings <a class="header-anchor" href="#_2-configurar-player-settings" aria-label="Permalink to &quot;2. Configurar Player Settings&quot;">​</a></h2><p>Para que el Tracker del plugin pueda distinguir matemáticamente entre los retrasos del procesador (CPU) y los de la tarjeta de video (GPU), necesita acceso a los tiempos exactos de los fotogramas del hardware.</p><div class="warning custom-block"><p class="custom-block-title">Estadísticas de Tiempo de Fotograma (Frame Timing Stats)</p><p>Navega a <strong>Edit -&gt; Project Settings -&gt; Player -&gt; Other Settings -&gt; Rendering</strong> y marca la casilla <strong>Frame Timing Stats</strong>. Sin esta configuración, la detección de Cuello de Botella (Bottleneck) no funcionará.</p></div><h2 id="_3-configurar-los-graficos" tabindex="-1">3. Configurar los Gráficos <a class="header-anchor" href="#_3-configurar-los-graficos" aria-label="Permalink to &quot;3. Configurar los Gráficos&quot;">​</a></h2><p>Deja de crear preajustes de calidad separados (Bajo, Medio, Alto) para diferentes dispositivos, lo que obliga al jugador a seleccionarlos manualmente.</p><div class="tip custom-block"><p class="custom-block-title">Maximiza la Calidad Gráfica</p><p>Configura tu proyecto para la máxima calidad. Para BiRP, hazlo en <code>Project Settings -&gt; Quality</code> y para URP, dentro de tu <code>URP Asset</code>. Si el dispositivo del jugador carece de Margen de Rendimiento (Performance Headroom), el plugin reducirá automáticamente la carga sin problemas durante la ejecución, utilizando únicamente los Scalers que has habilitado.</p></div>',12)])])}const h=i(s,[["render",l]]);export{f as __pageData,h as default};
